 {"id":"bd-d87","title":"[Time] Implement Sleep and Timeout Primitives","description":"# Sleep and Timeout Primitives

## Overview
Core sleep and timeout operations with both wall time (production) and virtual time (lab) support.

## Implementation Steps

### Step 1: Sleep Future
```rust
use std::future::Future;
use std::pin::Pin;
use std::time::{Duration, Instant};

/// Future that completes after a duration
pub struct Sleep {
    deadline: Instant,
    // Registration with timer driver
    entry: Option<TimerEntry>,
}

impl Sleep {
    fn new(deadline: Instant) -> Self {
        Self {
            deadline,
            entry: None,
        }
    }

    /// Get the deadline instant
    pub fn deadline(&self) -> Instant {
        self.deadline
    }

    /// Reset to a new deadline
    pub fn reset(&mut self, deadline: Instant) {
        self.deadline = deadline;
        if let Some(entry) = &mut self.entry {
            entry.reset(deadline);
        }
    }

    /// Check if deadline has passed
    pub fn is_elapsed(&self) -> bool {
        Instant::now() >= self.deadline
    }
}

impl Future for Sleep {
    type Output = ();

    fn poll(mut self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<()> {
        // Check if already elapsed
        if self.is_elapsed() {
            return Poll::Ready(());
        }

        // Register with timer driver if not yet
        if self.entry.is_none() {
            self.entry = Some(TimerDriver::current().register(self.deadline, cx.waker().clone()));
        }

        // Check again (timer might have fired during registration)
        if self.is_elapsed() {
            Poll::Ready(())
        } else {
            Poll::Pending
        }
    }
}

/// Sleep for a duration
pub fn sleep(duration: Duration) -> Sleep {
    Sleep::new(Instant::now() + duration)
}

/// Sleep until an instant
pub fn sleep_until(deadline: Instant) -> Sleep {
    Sleep::new(deadline)
}
```

### Step 2: Timeout Wrapper
```rust
/// Future with a timeout
pub struct Timeout<F> {
    future: F,
    delay: Sleep,
}

impl<F> Timeout<F> {
    pub fn new(future: F, timeout: Duration) -> Self {
        Self {
            future,
            delay: sleep(timeout),
        }
    }
}

impl<F: Future> Future for Timeout<F> {
    type Output = Result<F::Output, Elapsed>;

    fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
        // SAFETY: We never move the future
        let this = unsafe { self.get_unchecked_mut() };

        // Try the inner future first
        if let Poll::Ready(v) = unsafe { Pin::new_unchecked(&mut this.future) }.poll(cx) {
            return Poll::Ready(Ok(v));
        }

        // Check timeout
        if Pin::new(&mut this.delay).poll(cx).is_ready() {
            return Poll::Ready(Err(Elapsed::new()));
        }

        Poll::Pending
    }
}

/// Error returned when timeout elapses
#[derive(Debug, Clone, Copy)]
pub struct Elapsed(());

impl Elapsed {
    fn new() -> Self { Self(()) }
}

impl std::fmt::Display for Elapsed {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(f, "deadline has elapsed")
    }
}

impl std::error::Error for Elapsed {}

/// Wrap a future with a timeout
pub fn timeout<F: Future>(duration: Duration, future: F) -> Timeout<F> {
    Timeout::new(future, duration)
}

/// Wrap a future with a deadline
pub fn timeout_at<F: Future>(deadline: Instant, future: F) -> Timeout<F> {
    Timeout {
        future,
        delay: sleep_until(deadline),
    }
}
```

### Step 3: Timer Driver
```rust
use std::collections::BinaryHeap;
use std::sync::{Arc, Mutex};

/// Timer entry in the wheel
struct TimerEntry {
    id: u64,
    deadline: Instant,
    waker: Waker,
}

impl Ord for TimerEntry {
    fn cmp(&self, other: &Self) -> Ordering {
        // Reverse for min-heap
        other.deadline.cmp(&self.deadline)
    }
}

/// Timer driver (production mode)
pub struct TimerDriver {
    heap: Mutex<BinaryHeap<TimerEntry>>,
    next_id: AtomicU64,
}

impl TimerDriver {
    pub fn new() -> Self {
        Self {
            heap: Mutex::new(BinaryHeap::new()),
            next_id: AtomicU64::new(0),
        }
    }

    pub fn register(&self, deadline: Instant, waker: Waker) -> TimerHandle {
        let id = self.next_id.fetch_add(1, Ordering::Relaxed);
        let entry = TimerEntry { id, deadline, waker };
        self.heap.lock().unwrap().push(entry);
        TimerHandle { id }
    }

    /// Process expired timers
    pub fn process_timers(&self) -> Option<Duration> {
        let now = Instant::now();
        let mut heap = self.heap.lock().unwrap();

        while let Some(entry) = heap.peek() {
            if entry.deadline <= now {
                let entry = heap.pop().unwrap();
                entry.waker.wake();
            } else {
                return Some(entry.deadline - now);
            }
        }
        None // No timers
    }
}
```

### Step 4: Lab Virtual Time
```rust
/// Virtual time for deterministic testing
pub struct VirtualTime {
    now: AtomicU64, // Nanoseconds since epoch
    timers: Mutex<BinaryHeap<VirtualTimer>>,
}

impl VirtualTime {
    pub fn new() -> Self {
        Self {
            now: AtomicU64::new(0),
            timers: Mutex::new(BinaryHeap::new()),
        }
    }

    pub fn now(&self) -> VirtualInstant {
        VirtualInstant(self.now.load(Ordering::Acquire))
    }

    /// Advance time by duration
    pub fn advance(&self, duration: Duration) {
        let nanos = duration.as_nanos() as u64;
        let new_now = self.now.fetch_add(nanos, Ordering::Release) + nanos;
        self.fire_timers_until(new_now);
    }

    /// Advance to next timer (auto-advance)
    pub fn advance_to_next_timer(&self) -> bool {
        let timers = self.timers.lock().unwrap();
        if let Some(next) = timers.peek() {
            let target = next.deadline;
            drop(timers);
            self.now.store(target, Ordering::Release);
            self.fire_timers_until(target);
            true
        } else {
            false
        }
    }

    fn fire_timers_until(&self, now: u64) {
        let mut timers = self.timers.lock().unwrap();
        while let Some(timer) = timers.peek() {
            if timer.deadline <= now {
                let timer = timers.pop().unwrap();
                timer.waker.wake();
            } else {
                break;
            }
        }
    }
}
```

## Cancel-Safety
- sleep: cancel-safe, can be restarted
- timeout: cancel-safe, inner future may have side effects
- Timer registration: automatically cleaned up on drop

